const raw = $input.first().json;
const body = raw.body ?? raw;

const required = ['roleDescription', 'cvText', 'candidateName'];
const missing = required.filter((k) => !body[k] || String(body[k]).trim() === '');
if (missing.length) {
  throw new Error(`Missing required fields: ${missing.join(', ')}`);
}

const recordId = body.recordId ?? null;
const writeToAttio = body.writeToAttio !== false && Boolean(recordId);

return [{
  json: {
    recordId,
    roleDescription: String(body.roleDescription).trim(),
    cvText: String(body.cvText).trim(),
    candidateName: String(body.candidateName).trim(),
    linkedinUrl: body.linkedinUrl ?? null,
    roleTitle: body.roleTitle ?? null,
    writeToAttio,
    receivedAt: new Date().toISOString(),
  },
}];

const input = $('Normalize input').first().json;
return [{
  json: {
    recordId: input.recordId,
    roleDescription: input.roleDescription,
    cvText: input.cvText,
    candidateName: input.candidateName,
    linkedinUrl: input.linkedinUrl,
    roleTitle: input.roleTitle,
    approve: false,
  },
}];

const review = $('Build full review').first().json;
const decision = $('Wait for approval').first().json;

return [{
  json: {
    status: 'rejected',
    candidateName: review.candidateName,
    fitScore: review.fitScore,
    fitTier: review.fitTier,
    reviewSummary: review.reviewSummary,
    reviewerNotes: decision['Reviewer notes (optional)'] ?? null,
    message: 'Research completed but not approved — nothing written to Attio or sent externally.',
    reviewMarkdown: review.reviewMarkdown,
  },
}];

const review = $('Build full review').first().json;
const input = review.input;
return [{
  json: {
    recordId: input.recordId,
    roleDescription: input.roleDescription,
    cvText: input.cvText,
    candidateName: input.candidateName,
    linkedinUrl: input.linkedinUrl,
    roleTitle: input.roleTitle,
    approve: true,
  },
}];

const review = $('Build full review').first().json;
const decision = $('Wait for approval').first().json;
const attio = $('Attio write-back API').first().json;

return [{
  json: {
    status: 'approved',
    mode: 'attio_writeback',
    candidateName: review.candidateName,
    recordId: review.recordId,
    fitScore: attio.fit?.score ?? review.fitScore,
    fitTier: attio.fit?.tier ?? review.fitTier,
    twoLiner: attio.bundle?.twoLiner ?? review.twoLiner,
    reviewerNotes: decision['Reviewer notes (optional)'] ?? null,
    message: 'Approved — fit fields and HM note written to Attio via API (requires ATTIO_API_TOKEN on api/).',
    reviewMarkdown: review.reviewMarkdown,
    clientSubmittalDraft: review.clientSubmittalDraft,
    candidateEmailDraft: review.candidateEmailDraft,
    attioResult: attio,
  },
}];

const review = $('Build full review').first().json;
const decision = $('Wait for approval').first().json;

return [{
  json: {
    status: 'approved',
    mode: 'standalone',
    candidateName: review.candidateName,
    fitScore: review.fitScore,
    fitTier: review.fitTier,
    twoLiner: review.twoLiner,
    pros: review.pros,
    cons: review.cons,
    gapAnalysis: review.gapAnalysis,
    hmNote: review.hmNote,
    clientSubmittalDraft: review.clientSubmittalDraft,
    candidateEmailDraft: review.candidateEmailDraft,
    webBullets: review.webBullets,
    reviewerNotes: decision['Reviewer notes (optional)'] ?? null,
    message: 'Approved — standalone mode (no recordId). Copy drafts from this JSON or wire Slack/Email nodes here.',
    reviewMarkdown: review.reviewMarkdown,
    reviewSummary: review.reviewSummary,
  },
}];
